APM_STACK_TRACE_LIMIT = int(os.getenv("ELASTIC_APM_STACK_TRACE_LIMIT", "500"))
APM_SPAN_FRAMES_MIN_DURATION = os.getenv("ELASTIC_APM_SPAN_FRAMES_MIN_DURATION", "0ms")
