APM_SOURCE_LINES_ERROR_APP = int(os.getenv("ELASTIC_APM_SOURCE_LINES_ERROR_APP", "15"))
APM_SOURCE_LINES_ERROR_LIBRARY = int(os.getenv("ELASTIC_APM_SOURCE_LINES_ERROR_LIBRARY", "15"))
APM_CENTRAL_CONFIG = os.getenv("ELASTIC_APM_CENTRAL_CONFIG", "true")
