db = SQLAlchemy(app)
apm = ElasticAPM(app)


class Item(db.Model):
    __tablename__ = "items"
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(120), nullable=False)
    created_at = db.Column(db.Float, nullable=False, default=lambda: time.time())


@app.before_request
def _start_timer():
    g._start = time.perf_counter()


@app.after_request
def _after_request(resp: Response):
    try:
        duration_ms = (time.perf_counter() - getattr(g, "_start", time.perf_counter())) * 1000.0
        resp.headers["X-Request-Duration-ms"] = f"{duration_ms:.3f}"

        if apm and getattr(apm, "client", None):
            apm.client.set_custom_context(
                {
                    "http": {
                        "request": {
                            "method": request.method,
                            "path": request.path,
                            "query_string": request.query_string.decode("utf-8", errors="ignore"),
                            "headers": {k: v for k, v in request.headers.items()},
                            "body": request.get_data(as_text=True),
                        },
                        "response": {
                            "status_code": resp.status_code,
                            "headers": {k: v for k, v in resp.headers.items()},
                            "body": resp.get_data(as_text=True),
                        },
                    },
                    "timing": {"duration_ms": duration_ms},
                }
            )
    except Exception:
        logger.exception("Failed to attach full request/response context to APM")
    return resp


@app.errorhandler(Exception)
def _handle_exception(e: Exception):
    try:
        if apm and getattr(apm, "client", None):
            apm.capture_exception()
    except Exception:
        logger.exception("Failed to capture exception in APM")
    return jsonify({"error": str(e), "type": e.__class__.__name__}), 500


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok", "service": APP_NAME})


@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(silent=True) or {}
    name = payload.get("name") or "unnamed"
    item = Item(name=name)
    db.session.add(item)
    db.session.commit()
    return jsonify({"id": item.id, "name": item.name, "created_at": item.created_at}), 201


@app.route("/items", methods=["GET"])
def list_items():
    limit = int(request.args.get("limit", "50"))
    items = Item.query.order_by(Item.id.desc()).limit(limit).all()
    return jsonify([{"id": i.id, "name": i.name, "created_at": i.created_at} for i in items])


@app.route("/items/<int:item_id>", methods=["GET"])
def get_item(item_id: int):
    item: Optional[Item] = Item.query.get(item_id)
    if not item:
        return jsonify({"error": "not_found"}), 404
    return jsonify({"id": item.id, "name": item.name, "created_at": item.created_at})


@app.route("/slow", methods=["GET"])
def slow():
    t = float(request.args.get("t", "0.25"))
    time.sleep(max(0.0, min(t, 10.0)))
    return jsonify({"slept_seconds": t})


@app.route("/error", methods=["GET"])
def error():
    raise RuntimeError("Intentional error for APM stack trace capture")


def init_db():
    with app.app_context():
        db.create_all()


if __name__ == "__main__":
    init_db()
    app.run(host=os.getenv("HOST", "0.0.0.0"), port=int(os.getenv("PORT", "8000")), debug=True)